"""CRUD routes — generated by doql."""
from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session
from database import get_db
import models
import schemas

router = APIRouter(prefix='/api/v1')

# ── Node ──

@router.get("/nodes", response_model=list[schemas.NodeResponse])
def list_nodes(skip: int = 0, limit: int = 100, db: Session = Depends(get_db)):
    return db.query(models.Node).offset(skip).limit(limit).all()

@router.get("/nodes/{item_id}", response_model=schemas.NodeResponse)
def get_node(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Node).filter(models.Node.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Node not found")
    return obj

@router.post("/nodes", response_model=schemas.NodeResponse, status_code=201)
def create_node(data: schemas.NodeCreate, db: Session = Depends(get_db)):
    import uuid as _uuid
    payload = data.model_dump()
    payload.setdefault('id', str(_uuid.uuid4()))
    obj = models.Node(**payload)
    db.add(obj)
    db.commit()
    db.refresh(obj)
    return obj

@router.patch("/nodes/{item_id}", response_model=schemas.NodeResponse)
def update_node(item_id: str, data: schemas.NodeUpdate, db: Session = Depends(get_db)):
    obj = db.query(models.Node).filter(models.Node.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Node not found")
    for key, val in data.model_dump(exclude_unset=True).items():
        setattr(obj, key, val)
    db.commit()
    db.refresh(obj)
    return obj

@router.delete("/nodes/{item_id}", status_code=204)
def delete_node(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Node).filter(models.Node.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Node not found")
    db.delete(obj)
    db.commit()

